Strategy.StrategyData:
using System;
using WealthLab.Backtest;
using WealthLab.Core;
using WealthLab.Indicators;
//this is a modified version
namespace WealthScript1 
{
	public class AVWAP_After_3to4Day_Drop_NoATR : UserStrategyBase
	{
		// ===== PARAMETERS =====
		private const int MinDropDays = 3;
		private const int MaxDropDays = 4;

		private const int MaxHoldDays = 7;        // 7 daily bars
		private const int CooldownBars = 10;

		// ===== DOLLAR VOLUME FILTER =====
		private const int DvLen = 20;
		private const double MinAvgDollarVol = 5_000_000.0;   // $5M/day

		// ===== STATE =====
		private int _anchorBar = -1;
		private int _entryBarForEpisode = -1;

		private double _cumPV = 0;
		private double _cumVol = 0;

		private TimeSeries _avwap;

		// Dollar volume series + average
		private TimeSeries _dollarVol;
		private TimeSeries _avgDollarVol20;

		public override void Initialize(BarHistory bars)
		{
			_avwap = new TimeSeries(bars.DateTimes, true);
			_avwap.Description = "AVWAP";

			// Build DollarVol series: Close * Volume
			_dollarVol = new TimeSeries(bars.DateTimes, true);
			for (int i = 0; i < bars.Count; i++)
				_dollarVol[i] = bars.Close[i] * bars.Volume[i];

			// 20-day average DollarVol
			_avgDollarVol20 = SMA.Series(_dollarVol, DvLen);

			// warmup needs drop-days + dollar-vol length
			StartIndex = Math.Max(MaxDropDays + 1, DvLen + 1);
		}

		public override void Execute(BarHistory bars, int idx)
		{
			if (idx < StartIndex)
				return;

			// =====================================================
			// 1) Build AVWAP if episode active
			// =====================================================
			if (_anchorBar >= 0 && idx >= _anchorBar)
			{
				double typical = (bars.High[idx] + bars.Low[idx] + bars.Close[idx]) / 3.0;
				double v = bars.Volume[idx];

				_cumPV += typical * v;
				_cumVol += v;

				_avwap[idx] = (_cumVol > 0.0) ? (_cumPV / _cumVol) : double.NaN;
			}
			else
			{
				_avwap[idx] = double.NaN;
			}

			// =====================================================
			// 2) EXIT RULES
			// =====================================================
			for (int i = OpenPositions.Count - 1; i >= 0; i--)
			{
				Position pos = OpenPositions[i];
				if (pos.PositionType != PositionType.Long)
					continue;

				int barsHeld = idx - pos.EntryBar;

				if (!double.IsNaN(_avwap[idx]) && bars.Close[idx] >= _avwap[idx])
				{
					ClosePosition(pos, OrderType.Market);
				}
				else if (barsHeld >= MaxHoldDays)
				{
					ClosePosition(pos, OrderType.Market);
				}
			}

			// =====================================================
			// 3) Cooldown / episode control
			// =====================================================
			if (_entryBarForEpisode >= 0)
			{
				if (!HasOpenPosition(bars, PositionType.Long) &&
					idx - _entryBarForEpisode >= CooldownBars)
				{
					ResetEpisode();
				}
				return;
			}

			if (HasOpenPosition(bars, PositionType.Long))
				return;

			// =====================================================
			// 4) Detect 3–4 consecutive down closes
			//     + REQUIRE AvgDollarVol20 >= $5,000,000 AT EXPECTED ENTRY BAR (idx+1)
			// =====================================================
			for (int d = MinDropDays; d <= MaxDropDays; d++)
			{
				int a = idx - d;

				bool allDown = true;
				for (int k = a + 1; k <= idx; k++)
				{
					if (bars.Close[k] >= bars.Close[k - 1])
					{
						allDown = false;
						break;
					}
				}

				if (!allDown)
					continue;

				// Market order enters next bar: enforce liquidity on entry bar
				int entryIdx = idx + 1;
				if (entryIdx >= bars.Count)
					continue;

				double adv = _avgDollarVol20[entryIdx];
				if (double.IsNaN(adv) || adv < MinAvgDollarVol)
					continue;

				// ---- Trigger episode ----
				_anchorBar = a;
				_cumPV = 0;
				_cumVol = 0;

				// Build AVWAP from anchor to current bar immediately
				for (int t = _anchorBar; t <= idx; t++)
				{
					double typical = (bars.High[t] + bars.Low[t] + bars.Close[t]) / 3.0;
					double v = bars.Volume[t];

					_cumPV += typical * v;
					_cumVol += v;

					_avwap[t] = (_cumVol > 0.0) ? (_cumPV / _cumVol) : double.NaN;
				}

				// =========================================================
				// WL8-CORRECT: store anchor bar index in Position.Tag via positionTag
				// =========================================================
				int positionTag = _anchorBar; // -1 means "not set" (default)
				var tx = PlaceTrade(bars, TransactionType.Buy, OrderType.Market, 0, positionTag);
				if (tx != null)
					tx.SignalName = "ENTRY";

				_entryBarForEpisode = idx;
				break;
			}
		}

		private void ResetEpisode()
		{
			_anchorBar = -1;
			_entryBarForEpisode = -1;
			_cumPV = 0;
			_cumVol = 0;
		}
	}
}
